const payload=$input.item.json.body||$input.item.json;
const cliente=payload.cliente||"GERAL";
const principios=payload.principios||[];
const friccoes=payload.friccoes||[];
const dividas=payload.dividas||[];
const pendentes_abertos=payload.pendentes_abertos||[];
const documentos_mortos=payload.documentos_mortos||[];
const inconsistencias=payload.inconsistencias||[];
const ficou_no_ar=payload.ficou_no_ar||"";
const diretor_mencionou=payload.diretor_mencionou||"";
const data=payload.data||new Date().toLocaleDateString("pt-BR",{timeZone:"America/Sao_Paulo"});
const hora=payload.hora||new Date().toLocaleTimeString("pt-BR",{timeZone:"America/Sao_Paulo",hour:"2-digit",minute:"2-digit"});
const resumoPrincipios=principios.length>0?principios.map(function(p,i){return(i+1)+". "+p;}).join("\n"):"Nenhum principio novo";
const resumoFriccoes=friccoes.length>0?friccoes.map(function(f,i){return(i+1)+". "+f;}).join("\n"):"Nenhuma friccao";
const extraLinhas=[];
if(documentos_mortos.length>0)extraLinhas.push("Docs mortos: "+documentos_mortos.join(", "));
if(inconsistencias.length>0)extraLinhas.push("Inconsistencias: "+inconsistencias.join(", "));
if(ficou_no_ar)extraLinhas.push("Ficou no ar: "+ficou_no_ar);
if(diretor_mencionou)extraLinhas.push("Diretor mencionou: "+diretor_mencionou);
const extraBloco=extraLinhas.length>0?"\n\n"+extraLinhas.join("\n"):"";
const texto="Sessao encerrada -- "+data+" "+hora+"\nCliente: "+cliente+"\n\nPrincipios (+"+principios.length+"):\n"+resumoPrincipios+"\n\nFriccoes (+"+friccoes.length+"):\n"+resumoFriccoes+"\n\nDividas: "+dividas.length+extraBloco;
return [{json:{cliente,data,hora,texto,principios,friccoes,dividas,pendentes_abertos,documentos_mortos,inconsistencias,ficou_no_ar,diretor_mencionou}}];

const item = $("Processar Payload").item.json;
const tsStr = new Date().toISOString().replace("T"," ").slice(0,16) + " UTC";
const cliente = String(item.cliente || "?");
const principios = item.principios || [];
const friccoes_count = (item.friccoes || []).length;
const dividas = item.dividas || [];
const pendentes = item.pendentes_abertos || [];

// WIP Board
const wipChildren = [
    { object:"block", type:"divider", divider:{} },
    { object:"block", type:"callout", callout:{ rich_text:[{type:"text",text:{content:"🔒 Sessão encerrada · "+tsStr},annotations:{bold:true}}], icon:{type:"emoji",emoji:"🔒"}, color:"purple_background" } },
    { object:"block", type:"bulleted_list_item", bulleted_list_item:{ rich_text:[{type:"text",text:{content:"🗂️ Projeto: "+cliente}}] } },
    { object:"block", type:"bulleted_list_item", bulleted_list_item:{ rich_text:[{type:"text",text:{content:"📌 Princípios: +"+principios.length+" · Frições: "+friccoes_count+" · Dívidas: "+dividas.length+" · Pendentes: "+pendentes.length}}] } }
];

// Pendentes -- itens abertos do PENDENTES.md (OVERWRITE a cada session_close)
const pendChildren = [
    { object:"block", type:"divider", divider:{} },
    { object:"block", type:"callout", callout:{ rich_text:[{type:"text",text:{content:"📋 Pendentes Abertos · "+tsStr},annotations:{bold:true}}], icon:{type:"emoji",emoji:"📋"}, color:"blue_background" } }
];
const listaPend = pendentes.length > 0 ? pendentes : ["(sem pendentes abertos — all done ✅)"];
listaPend.forEach(p => {
    pendChildren.push({ object:"block", type:"bulleted_list_item", bulleted_list_item:{ rich_text:[{type:"text",text:{content:String(p)}}] } });
});
if (dividas.length > 0) {
    pendChildren.push({ object:"block", type:"divider", divider:{} });
    pendChildren.push({ object:"block", type:"callout", callout:{ rich_text:[{type:"text",text:{content:"⚠️ Dívidas Técnicas · "+tsStr},annotations:{bold:true}}], icon:{type:"emoji",emoji:"⚠️"}, color:"orange_background" } });
    dividas.forEach(d => {
        pendChildren.push({ object:"block", type:"numbered_list_item", numbered_list_item:{ rich_text:[{type:"text",text:{content:String(d)}}] } });
    });
}

// Ledger Vanguard -- novos principios (APPEND por sessao)
const ledgerChildren = [
    { object:"block", type:"divider", divider:{} },
    { object:"block", type:"callout", callout:{ rich_text:[{type:"text",text:{content:"📖 Sessão "+tsStr+" · "+cliente},annotations:{bold:true}}], icon:{type:"emoji",emoji:"📖"}, color:"gray_background" } }
];
const listaPrinc = principios.length > 0 ? principios : ["(sem novos princípios nesta sessão)"];
listaPrinc.forEach(p => {
    ledgerChildren.push({ object:"block", type:"bulleted_list_item", bulleted_list_item:{ rich_text:[{type:"text",text:{content:String(p)}}] } });
});

return [{ json: { wipChildren, pendChildren, ledgerChildren } }];

const pageId = $env.NOTION_PENDENTES_PAGE_ID;
const token = $env.NOTION_API_TOKEN;
const headers = { 'Authorization': 'Bearer ' + token, 'Notion-Version': '2022-06-28', 'Content-Type': 'application/json' };
try {
  const resp = await $http.get('https://api.notion.com/v1/blocks/' + pageId + '/children?page_size=100', { headers });
  const blocks = resp.results || (resp.data && resp.data.results) || [];
  for (const block of blocks) {
    try { await $http.delete('https://api.notion.com/v1/blocks/' + block.id, { headers }); } catch(e) {}
  }
  return [{ json: { limpar_ok: true, cleared: blocks.length } }];
} catch(e) {
  return [{ json: { limpar_ok: false, error: String(e.message) } }];
}

